46:     body    = [{ x: 13, y: 10 }, { x: 12, y: 10 }, { x: 11, y: 10 }];
47:     score   = 0;
48:     spawnFood();
49:     draw();
50:   }
51: 
52:   function spawnFood () {
53:     do {
54:       food = { x: Math.floor(Math.random() * W),
55:                y: Math.floor(Math.random() * H) };
56:     } while (body.some(s => s.x === food.x && s.y === food.y));
57:   }
