/**
 * @fileoverview Shared TypeScript interfaces for the CLI portfolio.
 *
 * This module defines all data types used across the terminal engine.
 * Import from here instead of defining inline types to maintain consistency.
 *
 * @module types
 * @see {@link file:///d:/portfolio-draft/docs/terminal-engine.md} for architecture overview
 */

// ── Portfolio Data Types ──────────────────────────────────────────

/** Information about the portfolio owner. */
export interface OwnerInfo {
  readonly name: string;
  readonly handle: string;
  readonly host: string;
  readonly title: string;
  readonly tagline: string;
  readonly location: string;
  readonly email: string;
  readonly github: string;
  readonly linkedin: string;
}

/** A single portfolio project entry. */
export interface Project {
  readonly slug: string;
  readonly name: string;
  readonly desc: string;
  readonly tech: readonly string[];
  readonly url: string;
  readonly year: number;
}

/** Skill categories mapped to arrays of skill names. */
export interface Skills {
  readonly [category: string]: readonly string[];
}

/** Contact information links. */
export interface Contact {
  readonly email: string;
  readonly github: string;
  readonly linkedin: string;
  readonly twitter: string;
}

/** Root shape of portfolio.json. */
export interface PortfolioData {
  readonly owner: OwnerInfo;
  readonly about: readonly string[];
  readonly skills: Skills;
  readonly projects: readonly Project[];
  readonly contact: Contact;
}

// ── Terminal Theme Types ──────────────────────────────────────────

/**
 * A complete terminal color theme compatible with xterm.js ITheme.
 * Themes are defined in themes.ts and can be switched at runtime via
 * the `theme` command.
 */
export interface TerminalTheme {
  /** Display name (e.g. "Amber Phosphor") */
  readonly name: string;
  /** Unique key used in the `theme <name>` command */
  readonly key: string;
  /** Main text color */
  readonly foreground: string;
  /** Terminal background */
  readonly background: string;
  /** Cursor block color */
  readonly cursor: string;
  /** Text behind cursor */
  readonly cursorAccent: string;
  /** Text selection highlight */
  readonly selectionBackground: string;
  /** ANSI color 0 – Black */
  readonly black: string;
  /** ANSI color 1 – Red */
  readonly red: string;
  /** ANSI color 2 – Green */
  readonly green: string;
  /** ANSI color 3 – Yellow */
  readonly yellow: string;
  /** ANSI color 4 – Blue */
  readonly blue: string;
  /** ANSI color 5 – Magenta */
  readonly magenta: string;
  /** ANSI color 6 – Cyan */
  readonly cyan: string;
  /** ANSI color 7 – White */
  readonly white: string;
  /** ANSI color 8 – Bright Black */
  readonly brightBlack: string;
  /** ANSI color 9 – Bright Red */
  readonly brightRed: string;
  /** ANSI color 10 – Bright Green */
  readonly brightGreen: string;
  /** ANSI color 11 – Bright Yellow */
  readonly brightYellow: string;
  /** ANSI color 12 – Bright Blue */
  readonly brightBlue: string;
  /** ANSI color 13 – Bright Magenta */
  readonly brightMagenta: string;
  /** ANSI color 14 – Bright Cyan */
  readonly brightCyan: string;
  /** ANSI color 15 – Bright White */
  readonly brightWhite: string;
}

// ── Command System Types ──────────────────────────────────────────

/**
 * Abstraction layer between commands and the terminal renderer.
 * Commands write output through this interface, making them
 * testable and decoupled from xterm.js internals.
 */
export interface TerminalWriter {
  /** Write text without a trailing newline. */
  write(text: string): void;
  /** Write text followed by \r\n. */
  writeln(text: string): void;
  /** Clear the entire terminal screen. */
  clear(): void;
}

/**
 * Handler function signature for terminal commands.
 * Each command receives parsed arguments and a writer for output.
 * Return a Promise for async commands (e.g. chatbot API calls).
 */
export type CommandHandler = (
  args: string[],
  writer: TerminalWriter
) => void | Promise<void>;

/**
 * Metadata for a registered command (used by help, tab completion).
 */
export interface CommandInfo {
  /** The command name (what the user types). */
  readonly name: string;
  /** Short description shown in `help` output. */
  readonly description: string;
  /** Usage example (e.g. "theme <name>"). */
  readonly usage?: string;
  /** The handler function. */
  readonly handler: CommandHandler;
}

/**
 * @fileoverview Global configuration constants for the CLI portfolio.
 *
 * Edit this file to change owner info, boot timing, audio settings,
 * or AI model configuration. All values are readonly to prevent
 * accidental mutation at runtime.
 *
 * @module config
 */

/** Application-wide configuration. */
export const CONFIG = {
  // ── Owner Identity ────────────────────────────────────────────
  owner: 'Joel Alfred Israel',
  handle: 'Joel01010',
  host: 'portfolio',

  // ── Boot Sequence ─────────────────────────────────────────────
  /** Delay between each boot line in ms. */
  bootLineDelay: 55,
  /** Typewriter speed per character in ms. */
  typeSpeed: 12,

  // ── Ambient Audio ─────────────────────────────────────────────
  /** Path to ambient audio file (relative to public/). */
  audioSrc: '/sounds/ambient.mp3',
  /** Default volume (0.0 – 1.0). */
  audioVol: 0.18,

  // ── Xiaomi MiMo API (Ezra Chatbot) ────────────────────────────
  /**
   * API endpoint for the Xiaomi MiMo chat completions.
   * OpenAI-compatible format.
   */
  mimoEndpoint: 'https://api.xiaomimimo.com/v1/chat/completions',
  /**
   * API key for authentication.
   * TODO: Move to environment variable / serverless function for production.
   * @see {@link file:///d:/portfolio-draft/docs/TECH_DEBT.md} for migration plan.
   */
  mimoApiKey: 'sk-s1h8cordp40kho0xo1hh7luq2jv7rtka5en02y2lxt3m2spm',
  /** Model identifier. */
  mimoModel: 'mimo-v2.5-pro',
  /** Maximum tokens in the AI response. */
  mimoMaxTokens: 512,

  // ── Chatbot ───────────────────────────────────────────────────
  /** Display name of the AI assistant. */
  botName: 'ezra',

  // ── Terminal ──────────────────────────────────────────────────
  /** Default theme key (must match a key in themes.ts). */
  defaultTheme: 'amber',
  /** Maximum command history entries. */
  historySize: 80,

  // ── Tab-Completable Commands ──────────────────────────────────
  /** List of all available command names for tab completion. */
  commands: [
    'help', 'ls', 'cd', 'cat', 'clear', 'about',
    'skills', 'projects', 'contact', 'ezra', 'neofetch',
    'theme', 'snake', 'reset',
  ],
} as const;

/** Type helper — extracts the config object type. */
export type Config = typeof CONFIG;

/**
 * @fileoverview Portfolio data loader with caching.
 *
 * Loads portfolio.json and ezra_system.md once, caches the result,
 * and returns typed data for use by commands and the chatbot.
 *
 * @module data
 */

import type { PortfolioData } from './types';

// ── Cache ─────────────────────────────────────────────────────────

let _portfolioCache: PortfolioData | null = null;
let _systemPromptCache: string | null = null;

/**
 * Load and cache portfolio data from portfolio.json.
 * Safe to call multiple times — returns cached data after first load.
 *
 * @returns Promise resolving to typed PortfolioData
 * @throws Error if the fetch fails or JSON is malformed
 */
export async function loadPortfolioData(): Promise<PortfolioData> {
  if (_portfolioCache) return _portfolioCache;

  const res = await fetch('/data/portfolio.json');
  if (!res.ok) {
    throw new Error(`Failed to load portfolio.json: ${res.status} ${res.statusText}`);
  }

  _portfolioCache = (await res.json()) as PortfolioData;
  return _portfolioCache;
}

/**
 * Load and cache the Ezra system prompt from ezra_system.md.
 * Safe to call multiple times — returns cached text after first load.
 *
 * @returns Promise resolving to the system prompt string
 */
export async function loadSystemPrompt(): Promise<string> {
  if (_systemPromptCache) return _systemPromptCache;

  const res = await fetch('/data/ezra_system.md');
  if (!res.ok) {
    throw new Error(`Failed to load ezra_system.md: ${res.status} ${res.statusText}`);
  }

  _systemPromptCache = await res.text();
  return _systemPromptCache;
}

/**
 * Get cached portfolio data synchronously.
 * Returns null if data hasn't been loaded yet.
 * Call loadPortfolioData() first during initialization.
 */
export function getPortfolioData(): PortfolioData | null {
  return _portfolioCache;
}

/**
 * Build a context string from portfolio data for the AI chatbot.
 * This is injected into the system prompt so Ezra knows about
 * Joel's projects, skills, and background.
 */
export function buildPortfolioContext(data: PortfolioData): string {
  const projectList = data.projects
    .map(p => `- ${p.name} (${p.year}): ${p.desc} [${p.tech.join(', ')}]`)
    .join('\n');

  const skillList = Object.entries(data.skills)
    .map(([cat, items]) => `- ${cat}: ${items.join(', ')}`)
    .join('\n');

  return [
    `## Portfolio Context`,
    `Name: ${data.owner.name}`,
    `Title: ${data.owner.title}`,
    `Location: ${data.owner.location}`,
    ``,
    `### About`,
    data.about.join(' '),
    ``,
    `### Projects`,
    projectList,
    ``,
    `### Skills`,
    skillList,
    ``,
    `### Contact`,
    `Email: ${data.contact.email}`,
    `GitHub: ${data.contact.github}`,
    `LinkedIn: ${data.contact.linkedin}`,
  ].join('\n');
}

/**
 * @fileoverview Virtual filesystem for the CLI portfolio.
 *
 * Provides ls, cd, cat operations over a simulated directory tree
 * built from portfolio data. The filesystem is initialized once
 * from PortfolioData and remains in memory.
 *
 * ## Directory Structure
 * ```
 * ~ (home)
 * ├── about/
 * │   ├── bio.txt
 * │   └── experience.txt
 * ├── skills/
 * │   ├── languages.txt
 * │   ├── frameworks.txt
 * │   └── devops.txt
 * ├── projects/
 * │   ├── <slug>.md  (one per project)
 * ├── contact/
 * │   └── links.txt
 * └── README.md
 * ```
 *
 * @module filesystem
 */

import type { PortfolioData, TerminalWriter } from './types';

// ── State ─────────────────────────────────────────────────────────

/** Directory tree: path → list of child names */
const fs = new Map<string, string[]>();

/** Current working directory */
let cwd = '~';

/** Cached portfolio data reference */
let _data: PortfolioData | null = null;

// ── Initialization ────────────────────────────────────────────────

/**
 * Initialize the virtual filesystem from portfolio data.
 * Call once after portfolio.json is loaded.
 *
 * @param data - Loaded portfolio data
 */
export function initFilesystem(data: PortfolioData): void {
  _data = data;
  cwd = '~';

  fs.clear();
  fs.set('~', ['about', 'skills', 'projects', 'contact', 'README.md']);
  fs.set('~/about', ['bio.txt', 'experience.txt']);
  fs.set('~/skills', ['languages.txt', 'frameworks.txt', 'devops.txt']);
  fs.set('~/projects', data.projects.map(p => `${p.slug}.md`));
  fs.set('~/contact', ['links.txt']);
}

// ── Path Resolution ───────────────────────────────────────────────

/**
 * Resolve a relative or absolute path to a full path.
 *
 * @param target - User-provided path (e.g. "..", "~", "projects")
 * @returns Resolved absolute path
 */
export function resolvePath(target: string): string {
  if (target === '..') {
    return cwd.includes('/') ? cwd.split('/').slice(0, -1).join('/') : '~';
  }
  if (target === '~') return '~';
  if (target.startsWith('~/')) return target;
  return cwd === '~' ? `~/${target}` : `${cwd}/${target}`;
}

// ── Operations ────────────────────────────────────────────────────

/** Get the current working directory path. */
export function getCwd(): string {
  return cwd;
}

/**
 * List contents of a directory.
 *
 * @param args - Optional target directory
 * @param writer - Terminal writer for output
 */
export function ls(args: string[], writer: TerminalWriter): void {
  const target = args[0] ? resolvePath(args[0]) : cwd;
  const contents = fs.get(target);

  if (!contents) {
    writer.writeln(`\x1b[31mls: cannot access '${args[0]}': No such file or directory\x1b[0m`);
    return;
  }

  if (contents.length === 0) {
    writer.writeln('\x1b[38;2;136;136;136m(empty)\x1b[0m');
    return;
  }

  const formatted = contents.map(item => {
    const isDir = fs.has(`${target}/${item}`) || fs.has(`~/${item}`);
    return isDir
      ? `\x1b[1;38;2;255;208;96m${item}/\x1b[0m`
      : `\x1b[38;2;255;176;0m${item}\x1b[0m`;
  });

  writer.writeln(formatted.join('  '));
}

/**
 * Change the current working directory.
 *
 * @param args - Target directory
 * @param writer - Terminal writer for output
 */
export function cd(args: string[], writer: TerminalWriter): void {
  if (!args[0] || args[0] === '~') {
    cwd = '~';
    writer.writeln(`\x1b[38;2;136;136;136mChanged to ~\x1b[0m`);
    return;
  }

  const target = resolvePath(args[0]);
  if (fs.has(target)) {
    cwd = target;
    writer.writeln(`\x1b[38;2;136;136;136mChanged to ${cwd}\x1b[0m`);
  } else {
    writer.writeln(`\x1b[31mcd: ${args[0]}: No such directory\x1b[0m`);
  }
}

/**
 * Print the contents of a virtual file.
 *
 * @param args - Filename to print
 * @param writer - Terminal writer for output
 */
export function cat(args: string[], writer: TerminalWriter): void {
  if (!args[0]) {
    writer.writeln('Usage: cat <file>');
    return;
  }

  if (!_data) {
    writer.writeln('\x1b[31mError: Portfolio data not loaded\x1b[0m');
    return;
  }

  const filename = args[0];

  // ── README.md ───────────────────────────────────────────
  if (filename === 'README.md') {
    writer.writeln('');
    writer.writeln(`\x1b[1;38;2;255;140;0m${_data.owner.name}'s Portfolio CLI\x1b[0m`);
    writer.writeln(`\x1b[38;2;255;176;0m${_data.owner.tagline}\x1b[0m`);
    writer.writeln('');
    writer.writeln(`Type \x1b[1;38;2;255;208;96mhelp\x1b[0m for available commands.`);
    writer.writeln('');
    return;
  }

  // ── bio.txt ─────────────────────────────────────────────
  if (filename === 'bio.txt') {
    _data.about.forEach(line => writer.writeln(`  ${line}`));
    return;
  }

  // ── experience.txt ──────────────────────────────────────
  if (filename === 'experience.txt') {
    writer.writeln(`  \x1b[1;38;2;255;140;0m${_data.owner.title}\x1b[0m`);
    writer.writeln(`  \x1b[38;2;136;136;136m${_data.owner.location}\x1b[0m`);
    return;
  }

  // ── Skill files ─────────────────────────────────────────
  if (filename === 'languages.txt' && _data.skills['Languages']) {
    _data.skills['Languages'].forEach(s => writer.writeln(`  \x1b[38;2;255;176;0m•\x1b[0m ${s}`));
    return;
  }
  if (filename === 'frameworks.txt') {
    const items = [
      ...(_data.skills['Frontend'] || []),
      ...(_data.skills['Backend'] || []),
    ];
    items.forEach(s => writer.writeln(`  \x1b[38;2;255;176;0m•\x1b[0m ${s}`));
    return;
  }
  if (filename === 'devops.txt' && _data.skills['AI/ML & Tools']) {
    _data.skills['AI/ML & Tools'].forEach(s => writer.writeln(`  \x1b[38;2;255;176;0m•\x1b[0m ${s}`));
    return;
  }

  // ── links.txt ───────────────────────────────────────────
  if (filename === 'links.txt') {
    const c = _data.contact;
    writer.writeln(`  Email:    ${c.email}`);
    writer.writeln(`  GitHub:   ${c.github}`);
    writer.writeln(`  LinkedIn: ${c.linkedin}`);
    if (c.twitter) writer.writeln(`  Twitter:  ${c.twitter}`);
    return;
  }

  // ── Project .md files ───────────────────────────────────
  if (filename.endsWith('.md') && filename !== 'README.md') {
    const slug = filename.replace('.md', '');
    const proj = _data.projects.find(p => p.slug === slug);
    if (proj) {
      writer.writeln('');
      writer.writeln(`\x1b[1;38;2;255;140;0m${proj.name}\x1b[0m  (${proj.year})`);
      writer.writeln(proj.desc);
      writer.writeln('');
      writer.writeln(`Tech: \x1b[38;2;255;208;96m${proj.tech.join(', ')}\x1b[0m`);
      writer.writeln(`URL:  ${proj.url}`);
      writer.writeln('');
      return;
    }
  }

  writer.writeln(`\x1b[31mcat: ${filename}: No such file\x1b[0m`);
}

/**
 * @fileoverview Creative neofetch command for the CLI portfolio.
 *
 * Renders a side-by-side ASCII art + system info display,
 * styled like the real Linux neofetch command.
 *
 * ## Output Layout
 * ```
 *  ┌──────────────┐    joel@portfolio
 *  │  ASCII ART   │    ──────────────────
 *  │  (14 lines)  │    OS: CLI-OS v4.2
 *  │              │    Host: portfolio.dev
 *  │              │    ...
 *  └──────────────┘    ██ ██ ██ ██ ██ ██
 * ```
 *
 * @module neofetch
 */

import type { TerminalWriter, PortfolioData } from './types';
import { CONFIG } from './config';
import { getAllThemeKeys } from './themes';

// ── ASCII Art ─────────────────────────────────────────────────────
// Custom terminal/laptop icon, 14 lines tall.
// Each line is padded to exactly 28 characters for alignment.

const ASCII_ART = [
  '   ╔══════════════════════╗ ',
  '   ║  ┌──────────────────┐║ ',
  '   ║  │ █▀▀▀▀▀▀▀▀▀▀▀▀▀█ │║ ',
  '   ║  │ █ joel@         █ │║ ',
  '   ║  │ █ portfolio  $_ █ │║ ',
  '   ║  │ █              █ │║ ',
  '   ║  │ █▄▄▄▄▄▄▄▄▄▄▄▄▄█ │║ ',
  '   ║  └──────────────────┘║ ',
  '   ╚══════════════════════╝ ',
  '   ╔══════════════════════╗ ',
  '   ║ ┃┃┃┃┃┃┃┃┃┃┃┃┃┃┃┃┃┃ ║ ',
  '   ║     ┌──────────┐     ║ ',
  '   ║     └──────────┘     ║ ',
  '   ╚══════════════════════╝ ',
];

/** Width of each ASCII art line (for alignment). */
const ART_WIDTH = 28;

// ── ANSI Color Helpers ────────────────────────────────────────────

const BOLD = '\x1b[1m';
const RESET = '\x1b[0m';

/** Color a string with an RGB foreground. */
function rgb(r: number, g: number, b: number, text: string): string {
  return `\x1b[38;2;${r};${g};${b}m${text}${RESET}`;
}

/** Bold + colored label. */
function label(text: string): string {
  return `${BOLD}${rgb(255, 140, 0, text)}`;
}

/** Dim value text. */
function value(text: string): string {
  return rgb(255, 208, 96, text);
}

// ── Uptime Calculation ────────────────────────────────────────────

/** Format milliseconds into a human-readable uptime string. */
function formatUptime(): string {
  const ms = performance.now();
  const seconds = Math.floor(ms / 1000);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);

  if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
  if (minutes > 0) return `${minutes}m ${seconds % 60}s`;
  return `${seconds}s`;
}

// ── Color Palette Bar ─────────────────────────────────────────────

/** Generate the classic neofetch color palette bar. */
function colorPalette(): string {
  const colors = [
    [0, 0, 0],       // black
    [255, 82, 82],    // red
    [0, 230, 118],    // green
    [255, 208, 96],   // yellow
    [128, 216, 255],  // blue
    [234, 128, 252],  // magenta
    [0, 229, 255],    // cyan
    [255, 176, 0],    // amber/white
  ];

  return colors
    .map(([r, g, b]) => `\x1b[48;2;${r};${g};${b}m   ${RESET}`)
    .join('');
}

// ── Main Renderer ─────────────────────────────────────────────────

/**
 * Render the neofetch display to the terminal.
 *
 * @param writer - Terminal writer for output
 * @param data - Portfolio data (for dynamic values)
 * @param currentTheme - Name of the currently active theme
 */
export function renderNeofetch(
  writer: TerminalWriter,
  data: PortfolioData | null,
  currentTheme: string
): void {
  const owner = data?.owner ?? { name: CONFIG.owner, handle: CONFIG.handle };
  const projectCount = data?.projects?.length ?? 0;
  const skillCount = data?.skills ? Object.keys(data.skills).length : 0;
  const themeCount = getAllThemeKeys().length;

  // Right-side info lines (must match ASCII_ART length: 14 lines)
  const infoLines: string[] = [
    `${BOLD}${rgb(255, 140, 0, `${CONFIG.handle}@${CONFIG.host}`)}`,
    rgb(136, 136, 136, '─'.repeat(24)),
    `${label('OS:')}         ${value('CLI-OS v4.2 (Amber)')}`,
    `${label('Host:')}       ${value('portfolio.dev')}`,
    `${label('Kernel:')}     ${value('xterm.js 5.5')}`,
    `${label('Uptime:')}     ${value(formatUptime())}`,
    `${label('Shell:')}      ${value('bash 5.2 (simulated)')}`,
    `${label('Resolution:')} ${value('680×440 (CRT)')}`,
    `${label('DE:')}         ${value('Laptop 3D')}`,
    `${label('WM:')}         ${value('CSS Perspective 1200px')}`,
    `${label('Theme:')}      ${value(`${currentTheme} (${themeCount} available)`)}`,
    `${label('CPU:')}        ${value(data?.owner?.name ?? CONFIG.owner)}`,
    `${label('GPU:')}        ${value(data?.owner?.title ?? 'CS Student')}`,
    `${label('Memory:')}     ${value(`${projectCount} projects / ${skillCount} skill trees`)}`,
  ];

  // Print side-by-side
  writer.writeln('');
  for (let i = 0; i < ASCII_ART.length; i++) {
    const art = rgb(255, 140, 0, ASCII_ART[i].padEnd(ART_WIDTH));
    const info = infoLines[i] ?? '';
    writer.writeln(`${art}  ${info}`);
  }

  // Color palette bar
  writer.writeln('');
  writer.writeln(`${''.padEnd(ART_WIDTH + 2)}${colorPalette()}`);
  writer.writeln(`${''.padEnd(ART_WIDTH + 2)}${colorPalette()}`);
  writer.writeln('');
}

/**
 * @fileoverview Ezra AI chatbot — Xiaomi MiMo API integration.
 *
 * Provides a multi-turn conversational AI assistant embedded in the
 * terminal. Uses the OpenAI-compatible Xiaomi MiMo API endpoint.
 *
 * ## Usage
 * The `ezra` command starts a sub-session. Users type messages and
 * get AI responses. Type "exit" or "quit" to return to the shell.
 *
 * ## Technical Debt
 * - API key is hardcoded (should use serverless proxy in production)
 * - No streaming support yet (could use SSE for real-time output)
 *
 * @module chatbot
 * @see {@link file:///d:/portfolio-draft/docs/TECH_DEBT.md}
 */

import type { TerminalWriter } from './types';
import { CONFIG } from './config';
import { loadPortfolioData, loadSystemPrompt, buildPortfolioContext } from './data';

// ── Types ─────────────────────────────────────────────────────────

interface ChatMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

interface MiMoResponse {
  choices: Array<{
    message: {
      content: string;
    };
  }>;
}

// ── State ─────────────────────────────────────────────────────────

let _active = false;
let _history: ChatMessage[] = [];
let _systemMessage = '';

// ── Public API ────────────────────────────────────────────────────

/** Check if the chatbot session is currently active. */
export function isActive(): boolean {
  return _active;
}

/**
 * Start a new Ezra chat session.
 * Loads the system prompt and portfolio context on first call.
 *
 * @param writer - Terminal writer for output
 */
export async function startChat(writer: TerminalWriter): Promise<void> {
  if (_active) {
    writer.writeln('\x1b[38;2;136;136;136mEzra is already running. Type "exit" to close.\x1b[0m');
    return;
  }

  _active = true;
  _history = [];

  // Build system prompt with portfolio context
  try {
    const [systemPrompt, data] = await Promise.all([
      loadSystemPrompt(),
      loadPortfolioData(),
    ]);
    const context = buildPortfolioContext(data);
    _systemMessage = `${systemPrompt}\n\n${context}`;
  } catch {
    _systemMessage = 'You are Ezra, a helpful AI assistant for Joel Alfred Israel\'s portfolio.';
  }

  writer.writeln('');
  writer.writeln('\x1b[1;38;2;0;229;255mEzra v2.0 — AI Assistant\x1b[0m');
  writer.writeln('\x1b[38;2;136;136;136mPowered by Xiaomi MiMo. Type your message. Type "exit" to return to shell.\x1b[0m');
  writer.writeln('');
}

/**
 * Handle user input during an active chat session.
 *
 * @param input - Raw user input string
 * @param writer - Terminal writer for output
 * @returns true if the session is still active, false if it ended
 */
export async function handleInput(input: string, writer: TerminalWriter): Promise<boolean> {
  const msg = input.trim();

  if (msg === '') return true;

  if (msg === 'exit' || msg === 'quit') {
    writer.writeln('\x1b[38;2;136;136;136mClosing Ezra. Returning to shell.\x1b[0m');
    writer.writeln('');
    _active = false;
    return false;
  }

  // Add user message
  _history.push({ role: 'user', content: msg });

  writer.writeln('\x1b[38;2;136;136;136mthinking...\x1b[0m');

  try {
    const reply = await callAPI();
    // Print response with cyan color
    writer.writeln(`\x1b[1;38;2;0;229;255mezra>\x1b[0m ${reply}`);
    writer.writeln('');
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Unknown error';
    writer.writeln(`\x1b[31mEzra error: ${message}\x1b[0m`);
    writer.writeln('');
  }

  return true;
}

/** Stop the chat session (e.g. when user runs another command). */
export function stopChat(): void {
  _active = false;
  _history = [];
}

// ── API Call ──────────────────────────────────────────────────────

/**
 * Send the conversation to the Xiaomi MiMo API.
 *
 * @returns The assistant's reply text
 * @throws Error if the API request fails
 */
async function callAPI(): Promise<string> {
  const messages: ChatMessage[] = [
    { role: 'system', content: _systemMessage },
    ..._history,
  ];

  const body = {
    model: CONFIG.mimoModel,
    max_tokens: CONFIG.mimoMaxTokens,
    messages,
  };

  const res = await fetch(CONFIG.mimoEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${CONFIG.mimoApiKey}`,
    },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const errBody = await res.json().catch(() => ({}));
    const errMsg = (errBody as Record<string, unknown>)?.error
      ? JSON.stringify((errBody as Record<string, unknown>).error)
      : res.statusText;
    throw new Error(errMsg);
  }

  const data = (await res.json()) as MiMoResponse;
  const reply = data.choices?.[0]?.message?.content ?? '(no response)';

  // Add to history for multi-turn
  _history.push({ role: 'assistant', content: reply });

  return reply;
}

/**
 * @fileoverview Easter eggs — Konami code + seasonal greetings.
 *
 * @module easter
 */

// ── Konami Code ───────────────────────────────────────────────────

const KONAMI_SEQUENCE = [
  'ArrowUp', 'ArrowUp', 'ArrowDown', 'ArrowDown',
  'ArrowLeft', 'ArrowRight', 'ArrowLeft', 'ArrowRight',
  'b', 'a',
];

let konamiIndex = 0;

/**
 * Initialize the Konami code listener.
 * When the full sequence is entered, the callback fires.
 *
 * @param onActivate - Callback when Konami code is completed
 * @returns Cleanup function to remove the listener
 */
export function initKonami(onActivate: () => void): () => void {
  const handler = (e: KeyboardEvent) => {
    if (e.key === KONAMI_SEQUENCE[konamiIndex]) {
      konamiIndex++;
      if (konamiIndex === KONAMI_SEQUENCE.length) {
        konamiIndex = 0;
        onActivate();
      }
    } else {
      konamiIndex = 0;
    }
  };

  document.addEventListener('keydown', handler);
  return () => document.removeEventListener('keydown', handler);
}

// ── Seasonal Greetings ────────────────────────────────────────────

/**
 * Returns a seasonal greeting if today is a notable date,
 * or null otherwise.
 */
export function getSeasonalGreeting(): string | null {
  const now = new Date();
  const month = now.getMonth() + 1; // 1-12
  const day = now.getDate();

  if (month === 10 && day === 31) return '🎃 Happy Halloween! Try: cat /spooky.txt';
  if (month === 12 && day === 25) return '🎄 Merry Christmas!';
  if (month === 1 && day === 1) return '🎆 Happy New Year!';
  if (month === 8 && day === 15) return '🇮🇳 Happy Independence Day!';
  if (month === 1 && day === 26) return '🇮🇳 Happy Republic Day!';

  return null;
}

/**
 * @fileoverview Snake mini-game (Canvas-based).
 *
 * Renders a snake game on a canvas overlay inside the terminal area.
 * Press arrow keys to steer, Q to quit.
 *
 * @module snake
 */

// ── Constants ─────────────────────────────────────────────────────

const TILE = 16;
const W = 26;   // tiles wide
const H = 20;   // tiles tall
const DELAY = 110; // ms per tick

// ── State ─────────────────────────────────────────────────────────

let canvas: HTMLCanvasElement | null = null;
let ctx: CanvasRenderingContext2D | null = null;
let running = false;
let timer: ReturnType<typeof setTimeout> | null = null;
let dir = { x: 1, y: 0 };
let nextDir = { x: 1, y: 0 };
let body: Array<{ x: number; y: number }> = [];
let food = { x: 0, y: 0 };
let score = 0;
let _onQuit: (() => void) | null = null;

// ── Keyboard Handler ──────────────────────────────────────────────

function onKey(e: KeyboardEvent): void {
  const map: Record<string, { x: number; y: number }> = {
    ArrowUp:    { x: 0, y: -1 },
    ArrowDown:  { x: 0, y: 1 },
    ArrowLeft:  { x: -1, y: 0 },
    ArrowRight: { x: 1, y: 0 },
  };

  if (map[e.key] && !(dir.x === -map[e.key].x && dir.y === -map[e.key].y)) {
    nextDir = map[e.key];
    e.preventDefault();
  }

  if (e.key === 'q' || e.key === 'Q') {
    cleanup();
  }
}

// ── Game Logic ────────────────────────────────────────────────────

function spawnFood(): void {
  do {
    food = {
      x: Math.floor(Math.random() * W),
      y: Math.floor(Math.random() * H),
    };
  } while (body.some(s => s.x === food.x && s.y === food.y));
}

function resetGame(): void {
  dir = { x: 1, y: 0 };
  nextDir = { x: 1, y: 0 };
  body = [{ x: 13, y: 10 }, { x: 12, y: 10 }, { x: 11, y: 10 }];
  score = 0;
  spawnFood();
  draw();
}

function tick(): void {
  if (!running) return;
  dir = nextDir;

  const head = {
    x: (body[0].x + dir.x + W) % W,
    y: (body[0].y + dir.y + H) % H,
  };

  // Self-collision
  if (body.some(s => s.x === head.x && s.y === head.y)) {
    gameOver();
    return;
  }

  body.unshift(head);

  if (head.x === food.x && head.y === food.y) {
    score++;
    spawnFood();
  } else {
    body.pop();
  }

  draw();
  timer = setTimeout(tick, DELAY);
}

function draw(): void {
  if (!ctx || !canvas) return;

  ctx.fillStyle = '#000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Grid dots
  ctx.fillStyle = '#1a0a00';
  for (let x = 0; x < W; x++) {
    for (let y = 0; y < H; y++) {
      ctx.fillRect(x * TILE + 7, y * TILE + 7, 2, 2);
    }
  }

  // Food
  ctx.fillStyle = '#ff5500';
  ctx.shadowColor = '#ff5500';
  ctx.shadowBlur = 8;
  ctx.fillRect(food.x * TILE + 2, food.y * TILE + 2, TILE - 4, TILE - 4);
  ctx.shadowBlur = 0;

  // Snake body with gradient
  body.forEach((seg, i) => {
    const t = 1 - (i / body.length) * 0.5;
    ctx!.fillStyle = `rgba(255,${Math.floor(176 * t)},0,1)`;
    ctx!.fillRect(seg.x * TILE + 1, seg.y * TILE + 1, TILE - 2, TILE - 2);
  });

  // Score
  ctx.fillStyle = '#ffb000';
  ctx.font = '11px monospace';
  ctx.fillText(`SCORE: ${score}`, 6, 14);
}

function gameOver(): void {
  running = false;
  if (!ctx || !canvas) return;

  ctx.fillStyle = 'rgba(0,0,0,0.7)';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = '#ff5500';
  ctx.font = 'bold 20px monospace';
  ctx.textAlign = 'center';
  ctx.fillText('GAME OVER', canvas.width / 2, canvas.height / 2 - 10);
  ctx.fillStyle = '#ffb000';
  ctx.font = '13px monospace';
  ctx.fillText(`Score: ${score}`, canvas.width / 2, canvas.height / 2 + 14);
  ctx.fillText('Press Q to exit', canvas.width / 2, canvas.height / 2 + 34);
  ctx.textAlign = 'left';
}

// ── Public API ────────────────────────────────────────────────────

/**
 * Launch the snake game inside a container element.
 *
 * @param container - DOM element to append the canvas to
 * @param onQuit - Callback when the game is closed
 */
export function launchSnake(container: HTMLElement, onQuit?: () => void): void {
  _onQuit = onQuit ?? null;
  running = false;

  // Create canvas
  canvas = document.createElement('canvas');
  canvas.width = W * TILE;
  canvas.height = H * TILE;
  canvas.style.cssText = `
    position: absolute; top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    z-index: 50; border: 2px solid #ffb000;
    background: #000; image-rendering: pixelated;
  `;
  canvas.setAttribute('aria-label', 'Snake game');

  ctx = canvas.getContext('2d');
  container.appendChild(canvas);

  document.addEventListener('keydown', onKey);
  resetGame();
  running = true;
  timer = setTimeout(tick, DELAY);
}

/**
 * Clean up the snake game — remove canvas, listeners, timers.
 */
export function cleanup(): void {
  running = false;
  if (timer) clearTimeout(timer);
  document.removeEventListener('keydown', onKey);
  if (canvas?.parentNode) canvas.parentNode.removeChild(canvas);
  canvas = null;
  ctx = null;
  _onQuit?.();
}

/**
 * @fileoverview Command registry and interpreter for the CLI portfolio.
 *
 * All terminal commands are registered here as typed handlers.
 * The interpreter parses user input and dispatches to the correct handler.
 *
 * ## Adding a new command
 * 1. Create a handler function: `(args, writer) => void`
 * 2. Register it in `COMMANDS` map at the bottom of this file
 * 3. Add the name to CONFIG.commands in config.ts for tab completion
 * 4. Update the help text in cmdHelp()
 *
 * @module commands
 */

import type { TerminalWriter, CommandHandler, PortfolioData } from './types';
import { CONFIG } from './config';
import { getPortfolioData } from './data';
import * as fs from './filesystem';
import { renderNeofetch } from './neofetch';
import { startChat, handleInput as chatInput, isActive as isChatActive } from './chatbot';
import { getAllThemes, getTheme } from './themes';

// ── State ─────────────────────────────────────────────────────────

/** Current theme key (tracked for neofetch display). */
let _currentTheme = CONFIG.defaultTheme;

/** Callback to apply a theme to the xterm instance. */
let _onThemeChange: ((themeKey: string) => void) | null = null;

/** Callback to launch snake game (needs DOM container). */
let _onSnakeLaunch: (() => void) | null = null;

/** Callback to reload the page. */
let _onReset: (() => void) | null = null;

/** Callback to clear the terminal. */
let _onClear: (() => void) | null = null;

// ── Setup ─────────────────────────────────────────────────────────

/**
 * Configure command system callbacks.
 * Call once during terminal initialization.
 */
export function setupCommands(opts: {
  onThemeChange: (themeKey: string) => void;
  onSnakeLaunch: () => void;
  onReset: () => void;
  onClear: () => void;
}): void {
  _onThemeChange = opts.onThemeChange;
  _onSnakeLaunch = opts.onSnakeLaunch;
  _onReset = opts.onReset;
  _onClear = opts.onClear;
}

/** Set the current theme key (used by neofetch display). */
export function setCurrentTheme(key: string): void {
  _currentTheme = key;
}

// ── Command Handlers ──────────────────────────────────────────────

const cmdHelp: CommandHandler = (_args, writer) => {
  writer.writeln('');
  writer.writeln('\x1b[1;38;2;255;140;0mAvailable Commands\x1b[0m');
  writer.writeln('');
  writer.writeln('  \x1b[38;2;255;176;0mhelp\x1b[0m           Show this message');
  writer.writeln('  \x1b[38;2;255;176;0mls\x1b[0m             List directory contents');
  writer.writeln('  \x1b[38;2;255;176;0mcd <dir>\x1b[0m       Change directory');
  writer.writeln('  \x1b[38;2;255;176;0mcat <file>\x1b[0m     Print file contents');
  writer.writeln('  \x1b[38;2;255;176;0mabout\x1b[0m          Quick bio');
  writer.writeln('  \x1b[38;2;255;176;0mskills\x1b[0m         Technical skills overview');
  writer.writeln('  \x1b[38;2;255;176;0mprojects\x1b[0m       Project showcase');
  writer.writeln('  \x1b[38;2;255;176;0mcontact\x1b[0m        How to reach me');
  writer.writeln('  \x1b[38;2;255;176;0mneofetch\x1b[0m       System info display');
  writer.writeln('  \x1b[38;2;255;176;0mtheme <name>\x1b[0m   Switch color theme');
  writer.writeln('  \x1b[38;2;255;176;0mezra\x1b[0m           Chat with AI assistant');
  writer.writeln('  \x1b[38;2;255;176;0msnake\x1b[0m          Play Snake game');
  writer.writeln('  \x1b[38;2;255;176;0mclear\x1b[0m          Clear the screen');
  writer.writeln('  \x1b[38;2;255;176;0mreset\x1b[0m          Reload portfolio');
  writer.writeln('');
  writer.writeln('  \x1b[38;2;85;85;85mHint: try exploring with ls and cd...\x1b[0m');
  writer.writeln('');
};

const cmdAbout: CommandHandler = (_args, writer) => {
  const data = getPortfolioData();
  if (!data) { writer.writeln('Data not loaded yet.'); return; }

  writer.writeln('');
  writer.writeln(`\x1b[1;38;2;255;140;0m${data.owner.name}\x1b[0m  —  ${data.owner.title}`);
  writer.writeln(`\x1b[38;2;136;136;136m${data.owner.location}\x1b[0m`);
  writer.writeln('');
  data.about.forEach(line => writer.writeln(`  ${line}`));
  writer.writeln('');
};

const cmdSkills: CommandHandler = (_args, writer) => {
  const data = getPortfolioData();
  if (!data) { writer.writeln('Data not loaded yet.'); return; }

  writer.writeln('');
  for (const [cat, items] of Object.entries(data.skills)) {
    writer.writeln(`\x1b[1;38;2;255;140;0m${cat}\x1b[0m`);
    writer.writeln(`  ${items.join('  ')}`);
    writer.writeln('');
  }
};

const cmdProjects: CommandHandler = (_args, writer) => {
  const data = getPortfolioData();
  if (!data) { writer.writeln('Data not loaded yet.'); return; }

  writer.writeln('');
  for (const p of data.projects) {
    writer.writeln(`\x1b[1;38;2;255;208;96m${p.name}\x1b[0m  (${p.year})`);
    writer.writeln(`  ${p.desc}`);
    writer.writeln(`  \x1b[38;2;136;136;136m${p.tech.join(', ')}\x1b[0m`);
    writer.writeln(`  ${p.url}`);
    writer.writeln('');
  }
  writer.writeln(`Type \x1b[1;38;2;255;176;0mcd projects && ls\x1b[0m to explore project files.`);
  writer.writeln('');
};

const cmdContact: CommandHandler = (_args, writer) => {
  const data = getPortfolioData();
  if (!data) { writer.writeln('Data not loaded yet.'); return; }

  const c = data.contact;
  writer.writeln('');
  writer.writeln(`  \x1b[38;2;255;176;0mEmail\x1b[0m    ${c.email}`);
  writer.writeln(`  \x1b[38;2;255;176;0mGitHub\x1b[0m   ${c.github}`);
  writer.writeln(`  \x1b[38;2;255;176;0mLinkedIn\x1b[0m ${c.linkedin}`);
  if (c.twitter) writer.writeln(`  \x1b[38;2;255;176;0mTwitter\x1b[0m  ${c.twitter}`);
  writer.writeln('');
};

const cmdNeofetch: CommandHandler = (_args, writer) => {
  const data = getPortfolioData();
  renderNeofetch(writer, data, _currentTheme);
};

const cmdTheme: CommandHandler = (args, writer) => {
  if (!args[0]) {
    // List available themes
    writer.writeln('');
    writer.writeln('\x1b[1;38;2;255;140;0mAvailable Themes\x1b[0m');
    writer.writeln('');
    for (const [key, theme] of getAllThemes()) {
      const marker = key === _currentTheme ? ' \x1b[38;2;0;230;118m← active\x1b[0m' : '';
      writer.writeln(`  \x1b[38;2;255;176;0m${key.padEnd(12)}\x1b[0m ${theme.name}${marker}`);
    }
    writer.writeln('');
    writer.writeln('Usage: \x1b[38;2;255;208;96mtheme <name>\x1b[0m');
    writer.writeln('');
    return;
  }

  const theme = getTheme(args[0]);
  if (!theme) {
    writer.writeln(`\x1b[31mtheme: '${args[0]}' not found. Type \x1b[1mtheme\x1b[0;31m to see available themes.\x1b[0m`);
    return;
  }

  _currentTheme = theme.key;
  _onThemeChange?.(theme.key);
  writer.writeln(`\x1b[38;2;0;230;118mTheme switched to ${theme.name}\x1b[0m`);
};

const cmdEzra: CommandHandler = async (_args, writer) => {
  await startChat(writer);
};

const cmdSnake: CommandHandler = (_args, writer) => {
  writer.writeln('\x1b[1;38;2;255;140;0mSNAKE\x1b[0m — Arrow keys to move. Q to quit.');
  _onSnakeLaunch?.();
};

const cmdClear: CommandHandler = (_args, _writer) => {
  _onClear?.();
};

const cmdReset: CommandHandler = (_args, _writer) => {
  _onReset?.();
};

// ── Command Registry ──────────────────────────────────────────────

/**
 * Map of command name → handler function.
 * To add a new command, add an entry here.
 */
const COMMANDS = new Map<string, CommandHandler>([
  ['help', cmdHelp],
  ['ls', (args, w) => fs.ls(args, w)],
  ['cd', (args, w) => fs.cd(args, w)],
  ['cat', (args, w) => fs.cat(args, w)],
  ['about', cmdAbout],
  ['skills', cmdSkills],
  ['projects', cmdProjects],
  ['contact', cmdContact],
  ['neofetch', cmdNeofetch],
  ['theme', cmdTheme],
  ['ezra', cmdEzra],
  ['snake', cmdSnake],
  ['clear', cmdClear],
  ['reset', cmdReset],
]);

// ── Interpreter ───────────────────────────────────────────────────

/**
 * Parse and execute a command string.
 *
 * @param input - Raw input from the terminal
 * @param writer - Terminal writer for output
 * @returns Promise that resolves when the command completes
 */
export async function interpret(input: string, writer: TerminalWriter): Promise<void> {
  const trimmed = input.trim();
  if (!trimmed) return;

  // If Ezra chatbot is active, route input there
  if (isChatActive()) {
    await chatInput(trimmed, writer);
    return;
  }

  const parts = trimmed.split(/\s+/);
  const name = parts[0].toLowerCase();
  const args = parts.slice(1);

  const handler = COMMANDS.get(name);
  if (handler) {
    await handler(args, writer);
  } else {
    writer.writeln(`\x1b[31m${name}: command not found. Type \x1b[1mhelp\x1b[0;31m for usage.\x1b[0m`);
  }
}

/**
 * Get the current prompt string with the current working directory.
 * Uses ANSI colors for the joel@portfolio:~$ format.
 */
export function getPrompt(): string {
  const cwdPath = fs.getCwd();
  return `\x1b[1;38;2;255;140;0m${CONFIG.handle}@${CONFIG.host}\x1b[0m:\x1b[38;2;255;208;96m${cwdPath}\x1b[0m$ `;
}

