/* ══════════════════════════════════════════════════════════════
   global.css — Foundation Styles & Design Tokens
   ══════════════════════════════════════════════════════════════
   This file defines the design system: CSS variables, reset,
   typography, background effects, and global utilities.

   See docs/styles.md for the complete design system reference.
   ────────────────────────────────────────────────────────────── */

/* ── Google Fonts ─────────────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;600&family=Share+Tech+Mono&display=swap');

/* ── Design Tokens (CSS Custom Properties) ────────────────────── */
:root {
  /* Primary palette — amber phosphor CRT */
  --amber:         #ffb000;
  --amber-bright:  #ffd060;
  --amber-dim:     #6e4c00;
  --amber-glow:    rgba(255, 176, 0, 0.15);
  --amber-subtle:  rgba(255, 176, 0, 0.06);

  /* Accent colors */
  --cyan:     #00e5ff;
  --green:    #00e676;
  --red:      #ff5252;
  --blue:     #80d8ff;
  --magenta:  #ea80fc;
  --yellow:   #ffd060;

  /* Backgrounds */
  --bg:          #000000;
  --bg-scene:    #050505;
  --bg-laptop:   #111111;
  --bg-bezel:    #0a0a0a;
  --bg-overlay:  rgba(0, 0, 0, 0.85);

  /* Typography */
  --font-mono:    'Share Tech Mono', 'JetBrains Mono', 'Courier New', monospace;
  --font-size:    15px;
  --line-height:  1.55;

  /* Spacing */
  --gap-xs:  4px;
  --gap-sm:  8px;
  --gap-md:  16px;
  --gap-lg:  24px;
  --gap-xl:  48px;

  /* Transitions */
  --ease-out:  cubic-bezier(0.22, 1, 0.36, 1);
  --duration:  0.3s;
}

/* ── Reset ─────────────────────────────────────────────────────── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

body {
  font-family: var(--font-mono);
  font-size: var(--font-size);
  line-height: var(--line-height);
  color: var(--amber);
  background: var(--bg-scene);
  overflow: hidden;
  min-height: 100vh;
  position: relative;
}

/* ── Animated Background Grid ─────────────────────────────────── */
/* Subtle dark grid pattern that moves very slowly — barely noticeable
   but adds depth. Uses pseudo-element to avoid z-index conflicts. */

body::before {
  content: '';
  position: fixed;
  inset: 0;
  z-index: -1;
  opacity: 0.08;
  background:
    /* Horizontal lines */
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 39px,
      rgba(255, 176, 0, 0.3) 39px,
      rgba(255, 176, 0, 0.3) 40px
    ),
    /* Vertical lines */
    repeating-linear-gradient(
      90deg,
      transparent,
      transparent 39px,
      rgba(255, 176, 0, 0.3) 39px,
      rgba(255, 176, 0, 0.3) 40px
    );
  background-size: 40px 40px;
  animation: grid-drift 60s linear infinite;
}

@keyframes grid-drift {
  from { transform: translate(0, 0); }
  to   { transform: translate(40px, 40px); }
}

/* ── Text Selection ───────────────────────────────────────────── */
::selection {
  background: var(--amber-dim);
  color: var(--amber-bright);
}

::-moz-selection {
  background: var(--amber-dim);
  color: var(--amber-bright);
}

/* ── Skip Link (Accessibility) ────────────────────────────────── */
.skip-link {
  position: absolute;
  top: -100px;
  left: 0;
  background: var(--amber);
  color: var(--bg);
  padding: 6px 14px;
  z-index: 999;
  font-size: 14px;
  border-radius: 0 0 6px 0;
  text-decoration: none;
  font-weight: 600;
  transition: top var(--duration) var(--ease-out);
}

.skip-link:focus {
  top: 0;
}

/* ── Audio Bar ────────────────────────────────────────────────── */
#audio-bar {
  position: fixed;
  bottom: 14px;
  right: 14px;
  z-index: 100;
}

.btn-mute {
  background: rgba(0, 0, 0, 0.5);
  border: 1px solid var(--amber-dim);
  color: var(--amber);
  font-size: 18px;
  padding: 6px 10px;
  border-radius: 6px;
  cursor: pointer;
  backdrop-filter: blur(6px);
  transition: background var(--duration), border-color var(--duration);
}

.btn-mute:hover {
  background: rgba(60, 30, 0, 0.7);
  border-color: var(--amber);
}

/* ── Utility: Visually Hidden ─────────────────────────────────── */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* ══════════════════════════════════════════════════════════════
   laptop.css — 3D Laptop Scene
   ══════════════════════════════════════════════════════════════
   Renders a perspective-correct 3D laptop with an animated
   lid-open effect, metallic borders, and ambient glow.

   Structure: #scene > #laptop > #lid > #screen-bezel + #base
   ────────────────────────────────────────────────────────────── */

/* ── Scene Container ──────────────────────────────────────────── */

#scene {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  perspective: 1200px;
  position: relative;
}

/* ── Laptop Body ──────────────────────────────────────────────── */

#laptop {
  position: relative;
  width: 680px;
  transform-style: preserve-3d;
}

/* ── Ambient Glow Under Laptop ─────────────────────────────────
   Soft amber reflection on the "desk surface" below the laptop. */

#laptop::after {
  content: '';
  position: absolute;
  bottom: -40px;
  left: 10%;
  width: 80%;
  height: 60px;
  background: radial-gradient(
    ellipse at center,
    rgba(255, 176, 0, 0.12) 0%,
    rgba(255, 176, 0, 0.04) 50%,
    transparent 100%
  );
  border-radius: 50%;
  filter: blur(20px);
  z-index: -1;
  pointer-events: none;
}

/* ── Lid / Screen ─────────────────────────────────────────────── */

#lid {
  width: 680px;
  height: 440px;
  background: var(--bg-laptop);

  /* Metallic gradient border instead of flat color */
  border: 3px solid transparent;
  background-clip: padding-box;
  border-image: linear-gradient(
    135deg,
    #555 0%,
    #333 40%,
    #444 60%,
    #555 100%
  ) 1;

  border-radius: 12px 12px 0 0;
  transform-origin: bottom center;
  transform-style: preserve-3d;

  /* Start: lid closed (nearly vertical, facing down) */
  transform: perspective(1200px) rotateX(-88deg);
  transition: none; /* JS controls animation via .open class */
}

/* Lid-open animation with spring-like bounce */
#lid.open {
  animation: lid-open 1.4s var(--ease-out) forwards;
}

@keyframes lid-open {
  0%   { transform: perspective(1200px) rotateX(-88deg); }
  60%  { transform: perspective(1200px) rotateX(8deg); }  /* overshoot */
  80%  { transform: perspective(1200px) rotateX(-3deg); } /* settle back */
  100% { transform: perspective(1200px) rotateX(0deg); }
}

/* ── Screen Bezel ─────────────────────────────────────────────── */

#screen-bezel {
  position: absolute;
  inset: 12px;
  background: var(--bg-bezel);
  border-radius: 6px;
  overflow: hidden;
}

/* ── Base (keyboard area) ─────────────────────────────────────── */

#base {
  width: 680px;
  height: 28px;
  background: linear-gradient(
    to bottom,
    #1a1a1a,
    #111
  );
  border: 2px solid #333;
  border-top: none;
  border-radius: 0 0 10px 10px;
  position: relative;
}

/* Keyboard key pattern */
#keyboard {
  height: 18px;
  margin: 4px 60px 0;
  background: repeating-linear-gradient(
    90deg,
    #222 0px,
    #222 18px,
    #1a1a1a 18px,
    #1a1a1a 20px
  );
  border-radius: 2px;
  opacity: 0.6;
}

/* Trackpad */
#trackpad {
  width: 120px;
  height: 8px;
  margin: 2px auto 0;
  background: #1e1e1e;
  border-radius: 3px;
}

/* ── Responsive ───────────────────────────────────────────────── */

@media (max-width: 720px) {
  #laptop, #lid, #base {
    width: 100vw;
  }

  #lid {
    height: 58vw;
  }

  /* Reduce ambient glow on mobile */
  #laptop::after {
    height: 30px;
    filter: blur(12px);
  }
}

/* ── Reduced Motion ───────────────────────────────────────────── */

@media (prefers-reduced-motion: reduce) {
  #lid {
    animation: none !important;
    transform: perspective(1200px) rotateX(0deg) !important;
  }

  @keyframes lid-open {
    from, to { transform: perspective(1200px) rotateX(0deg); }
  }
}

/* ══════════════════════════════════════════════════════════════
   crt.css — CRT Monitor Effects
   ══════════════════════════════════════════════════════════════
   Layered effects that simulate a CRT monitor:
   1. Scanline overlay (repeating gradient)
   2. Barrel-distortion vignette (inset box-shadow)
   3. Phosphor text glow (text-shadow on xterm)
   4. Screen flicker (subtle brightness oscillation)
   5. Power LED (pulsing amber indicator)
   ────────────────────────────────────────────────────────────── */

/* ── CRT Container ────────────────────────────────────────────── */

#crt-wrap {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: var(--bg);
}

/* ── Scanline Overlay ─────────────────────────────────────────── */

#scanlines {
  position: absolute;
  inset: 0;
  z-index: 10;
  pointer-events: none;
  background: repeating-linear-gradient(
    to bottom,
    transparent        0px,
    transparent        6px,
    rgba(0, 0, 0, 0.18) 6px,
    rgba(0, 0, 0, 0.18) 8px
  );
  animation: scanline-flicker 3.6s ease-in-out infinite;
}

@keyframes scanline-flicker {
  0%, 100% { opacity: 1.00; }
  30%      { opacity: 0.93; }
  60%      { opacity: 0.96; }
  75%      { opacity: 0.91; }
}

/* ── Barrel-Distortion Vignette ───────────────────────────────── */

#crt-curve {
  position: absolute;
  inset: 0;
  z-index: 9;
  pointer-events: none;
  border-radius: 8px;
  box-shadow:
    inset 0 0 80px 20px rgba(0, 0, 0, 0.6),     /* dark vignette */
    inset 0 0 8px 2px rgba(255, 176, 0, 0.06);   /* faint amber bloom */
}

/* ── Phosphor Text Glow ───────────────────────────────────────── */
/* Applied to xterm.js rows for the glowing phosphor look. */

#crt-wrap .xterm-rows {
  text-shadow:
    0 0 4px  rgba(255, 176, 0, 0.8),
    0 0 10px rgba(255, 120, 0, 0.25);
}

/* ── Screen Flicker ───────────────────────────────────────────── */
/* Very subtle brightness oscillation — barely perceptible,
   but adds to the CRT authenticity. */

#crt-wrap::after {
  content: '';
  position: absolute;
  inset: 0;
  z-index: 11;
  pointer-events: none;
  background: transparent;
  animation: screen-flicker 4.2s ease-in-out infinite;
}

@keyframes screen-flicker {
  0%, 100% { opacity: 0; }
  50%      { opacity: 0.015; background: rgba(255, 255, 255, 1); }
  52%      { opacity: 0; }
}

/* ── Power LED ────────────────────────────────────────────────── */
/* Small pulsing amber dot on the bezel, mimicking real monitor LED. */

#power-led {
  position: absolute;
  bottom: -20px;
  left: 50%;
  transform: translateX(-50%);
  width: 6px;
  height: 6px;
  background: var(--amber);
  border-radius: 50%;
  z-index: 20;
  box-shadow:
    0 0 6px 2px rgba(255, 176, 0, 0.6),
    0 0 14px 4px rgba(255, 176, 0, 0.2);
  animation: led-pulse 2s ease-in-out infinite;
}

@keyframes led-pulse {
  0%, 100% { opacity: 0.7; box-shadow: 0 0 6px 2px rgba(255, 176, 0, 0.4); }
  50%      { opacity: 1.0; box-shadow: 0 0 8px 3px rgba(255, 176, 0, 0.7); }
}

/* ── Accessibility: Reduced Motion ────────────────────────────── */

@media (prefers-reduced-motion: reduce) {
  #scanlines {
    animation: none;
  }

  #crt-wrap::after {
    animation: none;
    display: none;
  }

  #power-led {
    animation: none;
    opacity: 0.8;
  }
}

/* ══════════════════════════════════════════════════════════════
   terminal.css — xterm.js Overrides
   ══════════════════════════════════════════════════════════════
   Custom styles applied on top of the xterm.js default theme.
   Handles background transparency, scrollbar, cursor glow,
   link colors, and container sizing.
   ────────────────────────────────────────────────────────────── */

/* ── Terminal Container ───────────────────────────────────────── */
/* Fills the entire CRT wrap area. The xterm instance attaches here. */

#terminal-mount {
  position: absolute;
  inset: 0;
  padding: 8px;
  z-index: 1;
}

/* ── xterm.js Root ────────────────────────────────────────────── */

.xterm {
  width: 100%;
  height: 100%;
}

/* Make xterm background transparent so the CRT wrap's #000 shows */
.xterm .xterm-viewport {
  background-color: transparent !important;
}

.xterm .xterm-screen {
  background-color: transparent !important;
}

/* ── Custom Scrollbar ─────────────────────────────────────────── */

.xterm .xterm-viewport::-webkit-scrollbar {
  width: 6px;
}

.xterm .xterm-viewport::-webkit-scrollbar-track {
  background: rgba(0, 0, 0, 0.3);
  border-radius: 3px;
}

.xterm .xterm-viewport::-webkit-scrollbar-thumb {
  background: var(--amber-dim);
  border-radius: 3px;
  transition: background 0.2s;
}

.xterm .xterm-viewport::-webkit-scrollbar-thumb:hover {
  background: var(--amber);
}

/* Firefox scrollbar */
.xterm .xterm-viewport {
  scrollbar-width: thin;
  scrollbar-color: var(--amber-dim) transparent;
}

/* ── Cursor Glow ──────────────────────────────────────────────── */
/* Adds a soft amber glow around the cursor block. */

.xterm-cursor-layer .xterm-cursor {
  box-shadow: 0 0 6px 1px rgba(255, 176, 0, 0.5);
}

/* ── Link Colors ──────────────────────────────────────────────── */

.xterm .xterm-link-layer a,
.xterm-rows .xterm-link {
  color: var(--amber-bright) !important;
  text-decoration: underline;
  text-decoration-color: var(--amber-dim);
}

.xterm .xterm-link-layer a:hover,
.xterm-rows .xterm-link:hover {
  color: #ffffff !important;
  text-decoration-color: var(--amber);
}

/* ══════════════════════════════════════════════════════════════
   boot.css — Boot Sequence Overlay Styles
   ══════════════════════════════════════════════════════════════
   The boot overlay sits on top of the terminal during the
   BIOS/boot animation. It's hidden by default and shown
   via the `.active` class.
   ────────────────────────────────────────────────────────────── */

/* ── Overlay Container ────────────────────────────────────────── */

#boot-overlay {
  display: none;
  position: absolute;
  inset: 0;
  padding: var(--gap-md);
  z-index: 5;
  font-family: var(--font-mono);
  font-size: 13px;
  color: var(--amber);
  overflow: hidden;
  white-space: pre;
  line-height: 1.6;
  background: var(--bg);

  /* Smooth fade-out when boot completes */
  opacity: 1;
  transition: opacity 0.6s var(--ease-out);
}

/* Active state — shown during boot */
#boot-overlay.active {
  display: block;
}

/* Fading out state — triggered when boot completes */
#boot-overlay.fade-out {
  opacity: 0;
  pointer-events: none;
}

/* ── Boot Text Color Classes ──────────────────────────────────── */
/* Used inline on boot message spans for semantic coloring. */

.ok   { color: var(--green); }
.fail { color: var(--red); }
.info { color: var(--blue); }
.dim  { color: var(--amber-dim); }
.warn { color: var(--yellow); }

/* ── Boot Cursor ──────────────────────────────────────────────── */
/* Blinking block cursor shown at the end of the current boot line. */

.boot-cursor {
  display: inline-block;
  width: 8px;
  height: 14px;
  background: var(--amber);
  vertical-align: middle;
  margin-left: 2px;
  animation: boot-blink 0.6s step-end infinite;
}

@keyframes boot-blink {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0; }
}

