/**
 * ─────────────────────────────────────────────────────
 *  Terminal.tsx — Main React island wrapping xterm.js
 *
 *  Initializes an xterm.Terminal inside a DOM ref, loads
 *  FitAddon and WebLinksAddon, manages input buffering,
 *  command history, tab completion, and dispatches to
 *  the command interpreter.
 *
 *  Usage in Astro:
 *    <Terminal client:load />
 * ─────────────────────────────────────────────────────
 */

import { useEffect, useRef } from 'react';
import { Terminal as XTerm } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import '@xterm/xterm/css/xterm.css';

import { CONFIG } from '../terminal/config';
import { DEFAULT_THEME, getTheme } from '../terminal/themes';
import {
  interpret,
  getPrompt,
  setupCommands,
  setCurrentTheme,
} from '../terminal/commands';
import { loadPortfolioData } from '../terminal/data';
import { initFilesystem } from '../terminal/filesystem';
import { initKonami, getSeasonalGreeting } from '../terminal/easter';
import { launchSnake } from '../terminal/snake';
import type { TerminalWriter } from '../terminal/types';

/* ── ASCII art banner (hardcoded, no figlet library) ── */
const BANNER = [
  '     ██╗ ██████╗ ███████╗██╗     ',
  '     ██║██╔═══██╗██╔════╝██║     ',
  '     ██║██║   ██║█████╗  ██║     ',
  '██   ██║██║   ██║██╔══╝  ██║     ',
  '╚█████╔╝╚██████╔╝███████╗███████╗',
  ' ╚════╝  ╚═════╝ ╚══════╝╚══════╝',
];

/* ── Props ───────────────────────────────────────────── */

/** @interface TerminalProps */
export interface TerminalProps {
  /** Called once the terminal is mounted and ready. */
  onBoot?: () => void;
  /** Additional CSS class name for the mount container */
  className?: string;
}

/* ── Component ───────────────────────────────────────── */

/**
 * Terminal — Full xterm.js terminal island.
 *
 * Handles:
 * - xterm initialization with amber CRT theme
 * - FitAddon for responsive resizing
 * - WebLinksAddon for clickable URLs
 * - Keystroke buffering, Enter, Backspace, arrows
 * - Command history (up/down, max 80 entries)
 * - Tab completion from command list
 * - FIGlet banner, welcome message, seasonal greeting
 * - Command dispatch to commands.ts interpreter
 */
export default function Terminal({ onBoot, className }: TerminalProps) {
  const mountRef = useRef<HTMLDivElement>(null);
  const termRef = useRef<XTerm | null>(null);

  useEffect(() => {
    const container = mountRef.current;
    if (!container) return;

    /* ── Create terminal instance ───────────────────── */
    const term = new XTerm({
      theme: {
        foreground: DEFAULT_THEME.foreground,
        background: DEFAULT_THEME.background,
        cursor: DEFAULT_THEME.cursor,
        cursorAccent: DEFAULT_THEME.cursorAccent,
        selectionBackground: DEFAULT_THEME.selectionBackground,
        black: DEFAULT_THEME.black,
        red: DEFAULT_THEME.red,
        green: DEFAULT_THEME.green,
        yellow: DEFAULT_THEME.yellow,
        blue: DEFAULT_THEME.blue,
        magenta: DEFAULT_THEME.magenta,
        cyan: DEFAULT_THEME.cyan,
        white: DEFAULT_THEME.white,
        brightBlack: DEFAULT_THEME.brightBlack,
        brightRed: DEFAULT_THEME.brightRed,
        brightGreen: DEFAULT_THEME.brightGreen,
        brightYellow: DEFAULT_THEME.brightYellow,
        brightBlue: DEFAULT_THEME.brightBlue,
        brightMagenta: DEFAULT_THEME.brightMagenta,
        brightCyan: DEFAULT_THEME.brightCyan,
        brightWhite: DEFAULT_THEME.brightWhite,
      },
      fontFamily: "'Share Tech Mono', 'JetBrains Mono', 'Courier New', monospace",
      fontSize: 14,
      lineHeight: 1.3,
      cursorBlink: true,
      cursorStyle: 'block',
      allowTransparency: true,
      scrollback: 1000,
      convertEol: true,
    });

    termRef.current = term;

    /* ── Load addons ────────────────────────────────── */
    const fitAddon = new FitAddon();
    term.loadAddon(fitAddon);
    term.loadAddon(new WebLinksAddon());

    /* ── Mount to DOM ───────────────────────────────── */
    term.open(container);
    requestAnimationFrame(() => fitAddon.fit());

    /* ── Resize handler ─────────────────────────────── */
    const handleResize = () => fitAddon.fit();
    window.addEventListener('resize', handleResize);

    /* ── Terminal writer for commands ────────────────── */
    const writer: TerminalWriter = {
      write: (text: string) => term.write(text),
      writeln: (text: string) => term.writeln(text),
      clear: () => {
        term.clear();
        term.write('\x1b[H');
      },
    };

    /* ── Setup command system callbacks ──────────────── */
    setupCommands({
      onThemeChange: (themeKey: string) => {
        const t = getTheme(themeKey);
        if (t) {
          term.options.theme = {
            foreground: t.foreground,
            background: t.background,
            cursor: t.cursor,
            cursorAccent: t.cursorAccent,
            selectionBackground: t.selectionBackground,
            black: t.black,
            red: t.red,
            green: t.green,
            yellow: t.yellow,
            blue: t.blue,
            magenta: t.magenta,
            cyan: t.cyan,
            white: t.white,
            brightBlack: t.brightBlack,
            brightRed: t.brightRed,
            brightGreen: t.brightGreen,
            brightYellow: t.brightYellow,
            brightBlue: t.brightBlue,
            brightMagenta: t.brightMagenta,
            brightCyan: t.brightCyan,
            brightWhite: t.brightWhite,
          };
          setCurrentTheme(themeKey);
        }
      },
      onSnakeLaunch: () => {
        launchSnake(container, () => {
          term.write(getPrompt());
          term.focus();
        });
      },
      onReset: () => window.location.reload(),
      onClear: () => {
        writer.clear();
        term.write(getPrompt());
      },
    });

    /* ── Load data and init filesystem ──────────────── */
    loadPortfolioData()
      .then(data => initFilesystem(data))
      .catch(err => console.warn('Failed to load portfolio data:', err));

    /* ── Konami code easter egg ─────────────────────── */
    const cleanupKonami = initKonami(() => {
      term.writeln('');
      term.writeln('\x1b[1;38;2;255;0;255m🎮 KONAMI CODE ACTIVATED! 🎮\x1b[0m');
      term.writeln('\x1b[38;2;0;255;65mYou found the secret! Try: snake\x1b[0m');
      term.writeln('');
      term.write(getPrompt());
    });

    /* ── Input state ────────────────────────────────── */
    let inputBuffer = '';
    const history: string[] = [];
    let historyIndex = -1;
    let savedInput = '';
    let isProcessing = false;

    /* ── Print banner & welcome ─────────────────────── */
    term.writeln('');
    BANNER.forEach(line => {
      term.writeln(`\x1b[38;2;255;102;0m${line}\x1b[0m`);
    });
    term.writeln('');
    term.writeln(`\x1b[1;38;2;255;176;0mWelcome to ${CONFIG.owner}'s CLI Portfolio\x1b[0m`);
    term.writeln(`\x1b[38;2;136;136;136mType \x1b[1;38;2;255;208;96mhelp\x1b[0;38;2;136;136;136m to see available commands.\x1b[0m`);

    const greeting = getSeasonalGreeting();
    if (greeting) {
      term.writeln(`\x1b[38;2;0;230;118m${greeting}\x1b[0m`);
    }

    term.writeln('');
    term.write(getPrompt());

    /* ── Clear the current line ─────────────────────── */
    function clearLine() {
      term.write('\r\x1b[K');
      term.write(getPrompt());
    }

    /* ── Key handler ────────────────────────────────── */
    term.onData(async (data: string) => {
      if (isProcessing) return;

      const code = data.charCodeAt(0);

      // ── Enter ─────────────────────────────────────
      if (data === '\r' || data === '\n') {
        term.writeln('');
        const trimmed = inputBuffer.trim();

        if (trimmed) {
          if (history.length === 0 || history[history.length - 1] !== trimmed) {
            history.push(trimmed);
            if (history.length > CONFIG.historySize) history.shift();
          }

          isProcessing = true;
          await interpret(trimmed, writer);
          isProcessing = false;
        }

        inputBuffer = '';
        historyIndex = -1;
        savedInput = '';
        term.write(getPrompt());
        return;
      }

      // ── Backspace ─────────────────────────────────
      if (code === 127 || data === '\b') {
        if (inputBuffer.length > 0) {
          inputBuffer = inputBuffer.slice(0, -1);
          term.write('\b \b');
        }
        return;
      }

      // ── Tab ───────────────────────────────────────
      if (data === '\t') {
        const partial = inputBuffer.split(/\s+/).pop() || '';
        if (partial) {
          const matches = CONFIG.commands.filter(c => c.startsWith(partial));
          if (matches.length === 1) {
            const suffix = matches[0].slice(partial.length) + ' ';
            inputBuffer += suffix;
            term.write(suffix);
          } else if (matches.length > 1) {
            term.writeln('');
            term.writeln(matches.join('  '));
            term.write(getPrompt() + inputBuffer);
          }
        }
        return;
      }

      // ── Arrow keys ────────────────────────────────
      if (data.startsWith('\x1b[')) {
        const arrow = data.slice(2);

        if (arrow === 'A') { // Up
          if (history.length === 0) return;
          if (historyIndex === -1) {
            savedInput = inputBuffer;
            historyIndex = history.length;
          }
          if (historyIndex > 0) {
            historyIndex--;
            inputBuffer = history[historyIndex];
            clearLine();
            term.write(inputBuffer);
          }
          return;
        }

        if (arrow === 'B') { // Down
          if (historyIndex === -1) return;
          historyIndex++;
          if (historyIndex >= history.length) {
            historyIndex = -1;
            inputBuffer = savedInput;
            savedInput = '';
          } else {
            inputBuffer = history[historyIndex];
          }
          clearLine();
          term.write(inputBuffer);
          return;
        }

        return; // Ignore Left/Right for now
      }

      // ── Ctrl+C ────────────────────────────────────
      if (code === 3) {
        term.writeln('^C');
        inputBuffer = '';
        historyIndex = -1;
        term.write(getPrompt());
        return;
      }

      // ── Ctrl+L ────────────────────────────────────
      if (code === 12) {
        writer.clear();
        term.write(getPrompt() + inputBuffer);
        return;
      }

      // ── Printable characters ──────────────────────
      if (code >= 32) {
        inputBuffer += data;
        term.write(data);
      }
    });

    /* ── Focus on click ────────────────────────────── */
    container.addEventListener('click', () => term.focus());

    /* ── Signal ready ──────────────────────────────── */
    onBoot?.();

    /* ── Cleanup ───────────────────────────────────── */
    return () => {
      window.removeEventListener('resize', handleResize);
      cleanupKonami();
      term.dispose();
      termRef.current = null;
    };
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div
      ref={mountRef}
      id="terminal-mount"
      className={className || ''}
      role="application"
      aria-label="Interactive CLI terminal"
    />
  );
}

/**
 * ─────────────────────────────────────────────────────
 *  BootOverlay.tsx — React island for the BIOS boot sequence
 *
 *  Displays boot lines one-by-one with a typewriter effect,
 *  interpolating config values (owner name, hostname).
 *  After the last line, calls the onComplete callback so
 *  the page can transition to the terminal.
 *
 *  Usage in Astro:
 *    <BootOverlay client:load onComplete={() => { ... }} />
 * ─────────────────────────────────────────────────────
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import { CONFIG } from '../terminal/config';

/* ── Boot line definition ────────────────────────────── */

interface BootLine {
  text: string;
  cls: string;
}

const BOOT_LINES: BootLine[] = [
  { text: 'BIOS v2.1 — Detecting hardware...',                cls: 'dim'  },
  { text: '[  OK  ] CPU: x86_64 cortex-A72 @ 2.4GHz',        cls: 'ok'   },
  { text: '[  OK  ] RAM: 16 GB DDR4',                          cls: 'ok'   },
  { text: '[  OK  ] Display: Amber CRT 680×440',               cls: 'ok'   },
  { text: '[  OK  ] Keyboard: Model M (vintage)',               cls: 'ok'   },
  { text: '',                                                    cls: ''     },
  { text: 'Loading CLI-OS kernel v4.2...',                      cls: 'info' },
  { text: `[  OK  ] Mounting /home/${CONFIG.owner.toLowerCase().replace(/\s+/g, '')}`, cls: 'ok' },
  { text: '[  OK  ] Importing skill-set modules...',            cls: 'ok'   },
  { text: `[  OK  ] Starting virtual host: ${CONFIG.host}`,    cls: 'ok'   },
  { text: '[  OK  ] Activating CRT scanline driver',            cls: 'ok'   },
  { text: '[  OK  ] Injecting personality matrix...',           cls: 'ok'   },
  { text: '[  OK  ] Spawning AI assistant (Ezra)',              cls: 'ok'   },
  { text: '',                                                    cls: ''     },
  { text: '[[  OK  ]] System ready.',                           cls: 'ok'   },
];

/* ── Props ───────────────────────────────────────────── */

export interface BootOverlayProps {
  onComplete: () => void;
}

/* ── Component ───────────────────────────────────────── */

export default function BootOverlay({ onComplete }: BootOverlayProps) {
  const overlayRef = useRef<HTMLDivElement>(null);
  const [active, setActive] = useState(false);

  const typewriteLine = useCallback(
    (container: HTMLDivElement, line: BootLine): Promise<void> => {
      return new Promise((resolve) => {
        const span = document.createElement('span');
        span.className = line.cls || '';
        container.appendChild(span);
        container.appendChild(document.createTextNode('\n'));

        const text = line.text;
        if (!text) { resolve(); return; }

        let charIndex = 0;
        let lastTime = 0;

        const step = (timestamp: number) => {
          if (!lastTime) lastTime = timestamp;
          if (timestamp - lastTime >= CONFIG.typeSpeed) {
            span.textContent += text[charIndex] || '';
            charIndex++;
            lastTime = timestamp;
          }
          if (charIndex < text.length) {
            requestAnimationFrame(step);
          } else {
            resolve();
          }
        };

        requestAnimationFrame(step);
      });
    },
    []
  );

  useEffect(() => {
    const overlay = overlayRef.current;
    if (!overlay) return;

    let cancelled = false;
    const sleep = (ms: number) =>
      new Promise<void>(res => {
        const id = setTimeout(res, ms);
        if (cancelled) clearTimeout(id);
      });

    async function runBoot() {
      setActive(true);
      await sleep(400);

      for (const line of BOOT_LINES) {
        if (cancelled) return;
        await typewriteLine(overlay!, line);
        await sleep(CONFIG.bootLineDelay);
      }

      await sleep(600);
      if (cancelled) return;

      // Fade out
      overlay!.classList.add('fade-out');
      await sleep(550);

      setActive(false);
      onComplete();
    }

    runBoot();

    return () => { cancelled = true; };
  }, [onComplete, typewriteLine]);

  return (
    <div
      ref={overlayRef}
      id="boot-overlay"
      className={active ? 'active' : ''}
      role="status"
      aria-live="polite"
      aria-label="System boot sequence"
    />
  );
}

---
/**
 * ─────────────────────────────────────────────────────
 *  index.astro — Main page for Joel's CLI Portfolio
 *
 *  Composition order:
 *    Layout
 *      └─ Skip Link (accessibility)
 *      └─ LaptopShell (3D frame)
 *           └─ CRTScreen (effects wrapper)
 *                ├─ BootOverlay (client:load — typewriter boot)
 *                └─ Terminal (client:load — xterm.js island)
 *      └─ AudioBar (client:idle — ambient audio toggle)
 *
 *  Boot flow:
 *    1. Page loads → BootOverlay starts typewriting
 *    2. BootOverlay completes → window.__bootComplete()
 *    3. Script opens lid + shows terminal
 * ─────────────────────────────────────────────────────
 */

import Layout from '../layouts/Layout.astro';
import LaptopShell from '../components/LaptopShell.astro';
import CRTScreen from '../components/CRTScreen.astro';
import BootOverlay from '../components/BootOverlay.tsx';
import Terminal from '../components/Terminal.tsx';
import AudioBar from '../components/AudioBar.tsx';
---

<Layout>
  <!-- ── Accessibility Skip Link ───────────────────── -->
  <a href="#terminal-mount" class="skip-link">Skip to terminal</a>

  <!-- ── 3D Laptop Shell ───────────────────────────── -->
  <LaptopShell>
    <!-- ── CRT Effects Wrapper ───────────────────── -->
    <CRTScreen>
      <!-- Boot Overlay (React island) -->
      <BootOverlay client:load />

      <!-- Terminal (React island — starts hidden) -->
      <Terminal client:load />
    </CRTScreen>
  </LaptopShell>

  <!-- ── Audio Controls (lazy-loaded) ────────────── -->
  <AudioBar client:idle />

  <!--
    Boot Flow Controller
    Coordinates: boot overlay → lid open → terminal visible
  -->
  <script>
    // BootOverlay calls window.__bootComplete() when done
    declare global {
      interface Window {
        __bootComplete: () => void;
      }
    }

    window.__bootComplete = function () {
      const lid = document.getElementById('lid');
      const termMount = document.getElementById('terminal-mount');

      if (!lid || !termMount) return;

      // Open the lid (CSS animation)
      lid.classList.add('open');

      // After lid opens, show terminal
      lid.addEventListener(
        'animationend',
        () => {
          termMount.classList.add('visible');
          // Focus terminal for keyboard input
