/**
 * ─────────────────────────────────────────────────────
 *  easter.ts — Easter eggs & hidden commands
 *
 *  Contains:
 *  - Konami code listener
 *  - Seasonal greetings
 *  - Skill-showcasing hidden commands:
 *    matrix, sudo, hack, cowsay, fortune, rust,
 *    quantum, cuda, vim, btw, rm, whoami, ping,
 *    curl, binary, compile
 *
 *  @module easter
 * ─────────────────────────────────────────────────────
 */

import type { TerminalWriter } from './types';

// ── Konami Code ───────────────────────────────────────────────────

const KONAMI_SEQUENCE = [
  'ArrowUp', 'ArrowUp', 'ArrowDown', 'ArrowDown',
  'ArrowLeft', 'ArrowRight', 'ArrowLeft', 'ArrowRight',
  'b', 'a',
];

let konamiIndex = 0;

/**
 * Initialize the Konami code listener.
 * When the full sequence is entered, the callback fires.
 *
 * @param onActivate - Callback when Konami code is completed
 * @returns Cleanup function to remove the listener
 */
export function initKonami(onActivate: () => void): () => void {
  const handler = (e: KeyboardEvent) => {
    if (e.key === KONAMI_SEQUENCE[konamiIndex]) {
      konamiIndex++;
      if (konamiIndex === KONAMI_SEQUENCE.length) {
        konamiIndex = 0;
        onActivate();
      }
    } else {
      konamiIndex = 0;
    }
  };

  document.addEventListener('keydown', handler);
  return () => document.removeEventListener('keydown', handler);
}

// ── Seasonal Greetings ────────────────────────────────────────────

/**
 * Returns a seasonal greeting if today is a notable date,
 * or null otherwise.
 */
export function getSeasonalGreeting(): string | null {
  const now = new Date();
  const month = now.getMonth() + 1; // 1-12
  const day = now.getDate();

  if (month === 10 && day === 31) return '🎃 Happy Halloween! Try: cat /spooky.txt';
  if (month === 12 && day === 25) return '🎄 Merry Christmas!';
  if (month === 1 && day === 1) return '🎆 Happy New Year!';
  if (month === 8 && day === 15) return '🇮🇳 Happy Independence Day!';
  if (month === 1 && day === 26) return '🇮🇳 Happy Republic Day!';
  if (month === 3 && day === 14) return '🥧 Happy Pi Day! 3.14159265358979...';

  return null;
}

// ── Matrix Rain ───────────────────────────────────────────────────
// Shows off: JavaScript animation, Canvas API, requestAnimationFrame

/**
 * Renders a Matrix digital rain effect in the terminal
 * for a few seconds using pure ANSI sequences.
 */
export async function matrixRain(w: TerminalWriter): Promise<void> {
  const cols = 60;
  const chars = 'ᾧᾨᾩᾪᾫᾬᾭᾮᾯᾰᾱᾲᾳᾴᾶᾷᾸᾹᾺΆᾼ01234789ABCDEF';
  const drops = new Array(cols).fill(0);

  w.writeln('');
  w.writeln('\x1b[1;38;2;0;255;65m  ╔══════════════════════════════════════════════╗\x1b[0m');
  w.writeln('\x1b[1;38;2;0;255;65m  ║     THE MATRIX HAS YOU, JOEL...             ║\x1b[0m');
  w.writeln('\x1b[1;38;2;0;255;65m  ║     Follow the white rabbit. 🐇             ║\x1b[0m');
  w.writeln('\x1b[1;38;2;0;255;65m  ╚══════════════════════════════════════════════╝\x1b[0m');
  w.writeln('');

  const frames = 25;
  for (let f = 0; f < frames; f++) {
    let line = '  ';
    for (let c = 0; c < cols; c++) {
      if (Math.random() > 0.85) drops[c] = 0;
      const bright = drops[c] < 3;
      const ch = chars[Math.floor(Math.random() * chars.length)];
      if (bright) {
        line += `\x1b[1;38;2;0;255;65m${ch}\x1b[0m`;
      } else if (Math.random() > 0.3) {
        line += `\x1b[38;2;0;${100 + Math.floor(Math.random() * 80)};30m${ch}\x1b[0m`;
      } else {
        line += ' ';
      }
      drops[c]++;
    }
    w.writeln(line);
    await sleep(60);
  }

  w.writeln('');
  w.writeln('\x1b[38;2;0;255;65m  Wake up, Neo... I mean, recruiter. 😏\x1b[0m');
  w.writeln('\x1b[38;2;80;80;80m  [Built with: requestAnimationFrame, ANSI escape codes, TypeScript]\x1b[0m');
  w.writeln('');
}

