export function cowsay(args: string[], w: TerminalWriter): void {
  const msg = args.length > 0
    ? args.join(' ')
    : 'I use Astro btw';

  const border = '─'.repeat(msg.length + 2);

  w.writeln('');
  w.writeln(`  ┌${border}┐`);
  w.writeln(`  │ ${msg} │`);
  w.writeln(`  └${border}┘`);
  w.writeln('         \\   ^__^');
  w.writeln('          \\  (oo)\\_______');
  w.writeln('             (__)\\       )\\/\\');
  w.writeln('                 ||----w |');
  w.writeln('                 ||     ||');
  w.writeln('');
}

