// ── Ping ─────────────────────────────────────────────────────────

export async function ping(args: string[], w: TerminalWriter): Promise<void> {
  const host = args[0] || 'recruiter.com';
  w.writeln('');
  w.writeln(`  \x1b[38;2;255;208;96mPINGING ${host}\x1b[0m`);
  w.writeln('');

  for (let i = 0; i < 4; i++) {
    const ms = (Math.random() * 3 + 0.5).toFixed(1);
    await sleep(400);
    w.writeln(`  64 bytes from ${host}: seq=${i} ttl=64 time=\x1b[38;2;0;230;118m${ms}ms\x1b[0m`);
