/* ══════════════════════════════════════════════════════════════
   laptop.css — ThinkPad E14 Gen 6 Inspired 3D Scene
   ══════════════════════════════════════════════════════════════
   Renders a perspective-correct ThinkPad-style laptop with:
   - Brushed metal lid texture with ThinkPad logo
   - Red LED dot on the "i"
   - Perspective shift as lid opens
   - TrackPoint red nub
   - Hinge details

   Structure: #scene > #laptop > #lid > #lid-exterior + #lid-interior > #screen-bezel
   ────────────────────────────────────────────────────────────── */

/* ── Scene Container ──────────────────────────────────────────── */

#scene {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  perspective: 1100px;
  position: relative;
  /* Scene perspective shifts during lid open via animation */
  animation: scene-perspective-shift 2s var(--ease-out) forwards;
}

@keyframes scene-perspective-shift {
  0%   { perspective: 800px; transform: translateY(30px); }
  60%  { perspective: 1100px; transform: translateY(-5px); }
  100% { perspective: 1200px; transform: translateY(0); }
}

/* ── Laptop Body ──────────────────────────────────────────────── */

#laptop {
  position: relative;
  width: 780px;
  transform-style: preserve-3d;
  /* Subtle tilt — like looking slightly down at a desk */
  transform: rotateX(4deg);
  animation: laptop-settle 2s var(--ease-out) forwards;
}

@keyframes laptop-settle {
  0%   { transform: rotateX(12deg) scale(0.95); }
  60%  { transform: rotateX(2deg) scale(1.01); }
  100% { transform: rotateX(4deg) scale(1); }
}

/* ── Ambient Glow Under Laptop ─────────────────────────────────
   Soft amber reflection on the "desk surface" below the laptop. */

#laptop::after {
  content: '';
  position: absolute;
  bottom: -45px;
  left: 8%;
  width: 84%;
  height: 70px;
  background: radial-gradient(
    ellipse at center,
    rgba(255, 176, 0, 0.10) 0%,
    rgba(255, 176, 0, 0.03) 50%,
    transparent 100%
  );
  border-radius: 50%;
  filter: blur(25px);
  z-index: -1;
  pointer-events: none;
  opacity: 0;
  animation: glow-fadein 2.5s 1.2s ease forwards;
}

@keyframes glow-fadein {
  to { opacity: 1; }
}

/* ── Lid / Screen ─────────────────────────────────────────────── */

#lid {
  width: 780px;
  height: 500px;
  position: relative;
  transform-origin: bottom center;
  transform-style: preserve-3d;

  /* Start: lid closed (facing up, showing exterior) */
  transform: rotateX(-90deg);
  transition: none;
}

/* Lid-open animation with spring-like bounce + perspective shift */
#lid.open {
  animation: lid-open 1.8s var(--ease-out) forwards;
}

@keyframes lid-open {
  0%   { transform: rotateX(-90deg); }
  50%  { transform: rotateX(6deg); }
  70%  { transform: rotateX(-2deg); }
  100% { transform: rotateX(0deg); }
}

/* ═══════════════════════════════════════════════════════════════
   LID EXTERIOR — ThinkPad Back Cover
   The surface visible when the laptop is closed.
   Brushed grey metal texture with the iconic ThinkPad logo.
   ═══════════════════════════════════════════════════════════════ */

#lid-exterior {
  position: absolute;
  inset: 0;
  border-radius: 10px 10px 0 0;
  backface-visibility: hidden;
  /* Rotated so it faces backward (visible when lid is closed) */
  transform: rotateY(180deg) rotateX(180deg);
  z-index: 1;

  /* Brushed dark grey metal — ThinkPad E14 Gen 6 style */
  background:
    /* Subtle horizontal brush strokes */
    repeating-linear-gradient(
      0deg,
      transparent 0px,
      rgba(255,255,255,0.012) 1px,
      transparent 2px,
      transparent 4px
    ),
    /* Base gradient — dark charcoal with slight sheen */
    linear-gradient(
      165deg,
      #2a2a2e 0%,
      #1e1e22 25%,
      #222226 50%,
      #1a1a1e 75%,
      #2a2a2e 100%
    );

  /* Soft metallic sheen overlay */
  box-shadow:
    inset 0 0 80px rgba(255,255,255, 0.02),
    inset 0 1px 0 rgba(255,255,255, 0.06);

  border: 2px solid #333;
  border-bottom: none;
}

/* ── ThinkPad Logo (bottom-right of lid) ─────────────────────── */

#thinkpad-logo {
  position: absolute;
  bottom: 22px;
  right: 28px;
  font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
  font-weight: 700;
  font-size: 16px;
  letter-spacing: 0.5px;
  user-select: none;
  display: flex;
  align-items: center;
}

#thinkpad-logo .think {
  color: #888;
  font-weight: 300;
}

#thinkpad-logo .pad {
  color: #aaa;
  font-weight: 700;
}

/* Red LED dot — positioned over the "i" in Think */
#thinkpad-logo .led-dot {
  position: absolute;
  left: 26px;  /* aligned above the "i" */
  top: -1px;
  width: 5px;
  height: 5px;
  background: #e63030;
  border-radius: 50%;
  box-shadow:
    0 0 4px 1px rgba(230, 48, 48, 0.6),
    0 0 12px 3px rgba(230, 48, 48, 0.3);
  animation: led-pulse 2.5s ease-in-out infinite;
}

@keyframes led-pulse {
  0%, 100% { opacity: 0.8; box-shadow: 0 0 4px 1px rgba(230,48,48,0.5), 0 0 10px 2px rgba(230,48,48,0.2); }
  50%      { opacity: 1;   box-shadow: 0 0 6px 2px rgba(230,48,48,0.8), 0 0 16px 4px rgba(230,48,48,0.4); }
}

/* ── Lenovo Wordmark (bottom-left) ───────────────────────────── */

#lenovo-mark {
  position: absolute;
  bottom: 25px;
  left: 28px;
  font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
  font-size: 9px;
  font-weight: 400;
  letter-spacing: 3px;
  color: #555;
  user-select: none;
}

/* ═══════════════════════════════════════════════════════════════
   LID INTERIOR — Screen Side
   The surface visible when the laptop is open.
   ═══════════════════════════════════════════════════════════════ */

#lid-interior {
  position: absolute;
  inset: 0;
  background: var(--bg-laptop);
  border-radius: 10px 10px 0 0;
  backface-visibility: hidden;

  /* Thin bezel frame like E14 */
  border: 2px solid #2a2a2a;
  border-bottom: none;
  box-shadow:
    inset 0 0 0 4px #0d0d0d,
    inset 0 0 0 5px #1a1a1a;
}

/* ── Webcam Dot (top center of screen) ───────────────────────── */

#webcam {
  position: absolute;
  top: 5px;
  left: 50%;
  transform: translateX(-50%);
  width: 4px;
  height: 4px;
  background: #1a1a1a;
  border: 1px solid #333;
  border-radius: 50%;
  z-index: 5;
}

/* ── Screen Bezel ─────────────────────────────────────────────── */

#screen-bezel {
  position: absolute;
  top: 14px;
  left: 8px;
  right: 8px;
  bottom: 6px;
  background: var(--bg-bezel);
  border-radius: 4px;
  overflow: hidden;
}

/* ═══════════════════════════════════════════════════════════════
   BASE — Keyboard Tray
   ThinkPad-style with textured surface, red TrackPoint nub.
   ═══════════════════════════════════════════════════════════════ */

#base {
  width: 780px;
  height: 32px;
  position: relative;

  background:
    /* Subtle texture */
    repeating-linear-gradient(
      90deg,
      transparent 0px,
      rgba(255,255,255,0.008) 1px,
      transparent 2px,
      transparent 3px
    ),
    linear-gradient(to bottom, #1e1e1e, #141414);

  border: 2px solid #2a2a2a;
  border-top: 1px solid #222;
  border-radius: 0 0 8px 8px;
}

/* Keyboard key pattern */
#keyboard-area {
  position: relative;
  height: 20px;
  margin: 5px 50px 0;
}

#keyboard {
  height: 100%;
  background: repeating-linear-gradient(
    90deg,
    #1c1c1c 0px,
    #1c1c1c 16px,
    #141414 16px,
    #141414 18px
  );
  border-radius: 2px;
  opacity: 0.5;
}

/* ── Red TrackPoint Nub ──────────────────────────────────────── */

#thinkpad-nub {
  position: absolute;
  top: 7px;
  left: 50%;
  transform: translateX(-50%);
  width: 6px;
  height: 6px;
  background: radial-gradient(circle at 40% 35%, #e63030, #b01515);
  border-radius: 50%;
  box-shadow: 0 0 3px rgba(230, 48, 48, 0.3);
  z-index: 2;
}

/* Trackpad — wider, ThinkPad style */
#trackpad {
  width: 160px;
  height: 6px;
  margin: 1px auto 0;
  background: #181818;
  border: 1px solid #2a2a2a;
  border-radius: 3px;
}

/* ── Hinge Details ───────────────────────────────────────────── */

.hinge {
  position: absolute;
  top: -3px;
  width: 60px;
  height: 4px;
  background: linear-gradient(to bottom, #333, #222);
  border-radius: 2px;
}

#hinge-left  { left: 80px; }
#hinge-right { right: 80px; }

/* ══════════════════════════════════════════════════════════════
   RESPONSIVE
   ══════════════════════════════════════════════════════════════ */

@media (max-width: 820px) {
  #laptop, #lid, #base {
    width: 96vw;
    max-width: 780px;
  }

  #lid {
    height: 60vw;
    max-height: 500px;
  }

  #laptop::after {
    height: 30px;
    filter: blur(12px);
  }

  #thinkpad-logo { font-size: 13px; }
  #lenovo-mark { font-size: 8px; }
}

@media (max-width: 480px) {
  #thinkpad-logo,
  #lenovo-mark {
    display: none;
  }
}

/* ══════════════════════════════════════════════════════════════
   REDUCED MOTION
   ══════════════════════════════════════════════════════════════ */

@media (prefers-reduced-motion: reduce) {
  #lid {
    animation: none !important;
    transform: rotateX(0deg) !important;
  }

  #scene {
    animation: none !important;
    perspective: 1200px !important;
  }

  #laptop {
    animation: none !important;
    transform: rotateX(4deg) !important;
  }

  #thinkpad-logo .led-dot {
    animation: none !important;
    opacity: 1 !important;
  }

  @keyframes lid-open {
    from, to { transform: rotateX(0deg); }
  }
}

