        "url": "https://internshala.com/rss/internships/keywords-AI,ML,Python,React",
        "responseFormat": "string",
        "options": {}
      },
      "id": "fetch-internshala",
      "name": "Fetch Internshala RSS",
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.2,
      "position": [470, 300]
    },
    {
      "parameters": {
        "jsCode": "// Parse RSS XML into structured items\nconst xml = $input.first().json.data || $input.first().json.body || '';\nconst items = [];\nconst regex = /<item>([\\s\\S]*?)<\\/item>/g;\nlet match;\n\nwhile ((match = regex.exec(xml)) !== null) {\n  const block = match[1];\n  const title = (block.match(/<title>(?:<\\!\\[CDATA\\[)?(.*?)(?:\\]\\]>)?<\\/title>/) || [])[1] || '';\n  const link = (block.match(/<link>(.*?)<\\/link>/) || [])[1] || '';\n  const company = (block.match(/<company>(?:<\\!\\[CDATA\\[)?(.*?)(?:\\]\\]>)?<\\/company>/) || [])[1] || title.split(' at ').pop() || '';\n  const description = (block.match(/<description>(?:<\\!\\[CDATA\\[)?(.*?)(?:\\]\\]>)?<\\/description>/) || [])[1] || '';\n  \n  items.push({\n    json: {\n      title: title.trim(),\n      company: company.trim(),\n      url: link.trim(),\n      description: description.substring(0, 500).trim(),\n      date: new Date().toISOString().split('T')[0],\n      status: 'new'\n    }\n  });\n}\n\nreturn items.length > 0 ? items : [{ json: { error: 'No items parsed', raw: xml.substring(0, 200) } }];"
      },
      "id": "parse-rss",
      "name": "Parse RSS",
      "type": "n8n-nodes-base.code",
      "typeVersion": 2,
      "position": [690, 300]
    },
    {
      "parameters": {
        "model": "gpt-4o-mini",
        "messages": {
          "values": [
            {
              "role": "system",
              "content": "You are a job matching assistant. Score this internship 1-10 for Joel Alfred Israel, a 2nd-year CS student at VIT Chennai with skills in: Python, C/C++, Java, Rust, TypeScript, React, Flutter, CUDA, WASM. He has a published research paper on WASM for edge systems, NVIDIA CUDA certification, and projects in AI/ML. Return JSON: {\"score\": N, \"reasoning\": \"...\", \"cover_letter\": \"...\" (only if score >= 7)}"
            },
            {
              "role": "user",
              "content": "Title: {{ $json.title }}\nCompany: {{ $json.company }}\nDescription: {{ $json.description }}\nURL: {{ $json.url }}"
            }
          ]
        },
        "options": {
          "baseURL": "http://localhost:4000/v1",
          "temperature": 0.3
        }
      },
      "id": "ai-scorer",
      "name": "AI Score & Cover Letter",
      "type": "@n8n/n8n-nodes-langchain.openAi",
      "typeVersion": 1.5,
      "position": [910, 300]
    },
    {
      "parameters": {
        "rules": {
          "values": [
            {
              "conditions": {
                "options": { "caseSensitive": true, "leftValue": "", "typeValidation": "strict" },
                "conditions": [
                  { "leftValue": "={{ $json.message.content }}", "rightValue": "7", "operator": { "type": "number", "operation": "gte" } }
                ]
              },
              "renameOutput": "High Match (7+)"
            }
          ]
        },
        "fallbackOutput": "Low Match"
      },
      "id": "score-filter",
      "name": "Score >= 7?",
      "type": "n8n-nodes-base.switch",
      "typeVersion": 3.2,
      "position": [1130, 300]
    },
    {
      "parameters": {
        "sendTo": "joel010.alfred@gmail.com",
        "subject": "=Application Draft: {{ $('Parse RSS').item.json.title }} at {{ $('Parse RSS').item.json.company }}",
        "message": "={{ $json.message.content }}",
        "options": { "createDraft": true }
      },
      "id": "gmail-draft",
      "name": "Create Gmail Draft",
      "type": "n8n-nodes-base.gmail",
      "typeVersion": 2.1,
      "position": [1350, 200],
      "credentials": { "gmailOAuth2": { "id": "gmail-cred", "name": "Gmail Joel" } }
    },
    {
      "parameters": {
        "documentId": { "__rl": true, "mode": "url", "value": "" },
        "sheetName": { "__rl": true, "mode": "name", "value": "Applications" },
        "columns": {
          "mappingMode": "defineBelow",
          "value": {
            "Date": "={{ $('Parse RSS').item.json.date }}",
            "Company": "={{ $('Parse RSS').item.json.company }}",
            "Role": "={{ $('Parse RSS').item.json.title }}",
            "URL": "={{ $('Parse RSS').item.json.url }}",
            "Score": "={{ $json.score || 'N/A' }}",
            "Status": "new",
            "CoverLetterDrafted": "={{ $json.cover_letter ? 'Yes' : 'No' }}"
          }
        },
        "options": {}
      },
      "id": "sheets-log",
      "name": "Log to Sheets",
      "type": "n8n-nodes-base.googleSheets",
      "typeVersion": 4.5,
      "position": [1350, 400],
      "credentials": { "googleSheetsOAuth2Api": { "id": "sheets-cred", "name": "Google Sheets Joel" } }
    },
    {
      "parameters": {
        "chatId": "",
        "text": "=📋 **Internship Scout Report** ({{ new Date().toLocaleDateString() }})\n\nScanned {{ $('Parse RSS').all().length }} listings\nHigh matches (7+): {{ $('Score >= 7?').first() ? 'Found!' : 'None today' }}\n\nCheck Gmail Drafts for cover letters.",
        "additionalFields": { "parse_mode": "Markdown" }
      },
